// ── Step UI helpers ──────────────────────────────────────────────────
function choiceTile(value, active, icon, title, sub) {
  return `
    <button class="choice${active ? " active" : ""}" type="button" data-choice="${escapeHtml(value)}">
      <i data-lucide="${icon}"></i>
      <strong>${escapeHtml(title)}</strong>
      <span>${escapeHtml(sub)}</span>
    </button>
  `;
}
function bindChoices(root, fn) {
  root.querySelectorAll("[data-choice]").forEach((b) =>
    b.addEventListener("click", () => fn(b.dataset.choice))
  );
}

// ── Item-attribute steps (one Model link per family) ─────────────────
function attributeExamplesFor(family) {
  const palette = (industryAttributePalette[state.industry] || []).filter((item) => item.f === family).map((item) => item.n);
  const seen = new Set(palette.map((name) => name.toLowerCase()));
  const extras = (familyBase[family] || []).filter((name) => !seen.has(name.toLowerCase()));
  return { palette, extras };
}
function attributeChip(family, name, active) {
  return `<button class="attr-chip${active ? " active" : ""}" type="button" data-attr-family="${escapeHtml(family)}" data-attr-name="${escapeHtml(name)}">${escapeHtml(name)}</button>`;
}
function attributeSlot(familyId) {
  if (!state.attr) state.attr = {};
  if (!state.attr[familyId]) state.attr[familyId] = { picks: [], confirmed: false };
  return state.attr[familyId];
}
function makeAttributeStep(concept) {
  return {
    id: `attr-${concept.id}`, phase: "Model", nav: concept.short,
    title: () => `What ${concept.name.toLowerCase()} does your ${itemTerm()} carry?`,
    sub: () => `In ${profile().badge} these are modeled as ${attributeProfile()[concept.dialectKey]}. Pick the ones that matter — pre-populated for ${industry()?.name || "your industry"} and kept representative until customer master data replaces them.`,
    hint: "Select the attributes that apply, or mark none, to continue.",
    gate: () => { const slot = attributeSlot(concept.id); return slot.picks.length > 0 || slot.confirmed; },
    body: () => {
      const slot = attributeSlot(concept.id);
      const { palette, extras } = attributeExamplesFor(concept.id);
      const ap = attributeProfile();
      const lens = concept.id === "quality" && qualityLens();
      return `
        <div class="industry-synthesis">
          <i data-lucide="${concept.icon}"></i>
          <div><strong>${escapeHtml(ap[concept.dialectKey])}</strong><p>${escapeHtml(concept.role)} ${escapeHtml(concept.aps)}</p></div>
          <span>${escapeHtml(profile().badge)} dialect</span>
        </div>
        ${palette.length ? `
          <p class="attr-suggested-label">${escapeHtml(industry()?.name || "Industry")} examples</p>
          <div class="attr-chips">${palette.map((name) => attributeChip(concept.id, name, slot.picks.includes(name))).join("")}</div>` : ""}
        <p class="attr-suggested-label">Common ${escapeHtml(profile().badge)} fields</p>
        <div class="attr-chips">
          ${extras.map((name) => attributeChip(concept.id, name, slot.picks.includes(name))).join("")}
          <button class="attr-chip none${slot.confirmed && slot.picks.length === 0 ? " active" : ""}" type="button" data-attr-none="${concept.id}"><i data-lucide="ban"></i>None apply</button>
        </div>
        ${lens ? `<p class="representative-note attribute-lens"><i data-lucide="microscope"></i> Regulated / process lens: <b>CQA</b> = what must be true of the product (e.g. dissolution rate); <b>CPP</b> = what must be controlled in the process (e.g. mixing speed, drying temperature). MES captures these as process parameters and electronic batch-record values.</p>` : ""}
        ${slot.picks.length ? `<p class="representative-note"><i data-lucide="check"></i> ${slot.picks.length} attribute${slot.picks.length === 1 ? "" : "s"} captured.</p>` : ""}
      `;
    },
    attach: (root) => {
      const slot = attributeSlot(concept.id);
      root.querySelectorAll("[data-attr-name]").forEach((button) => button.addEventListener("click", () => {
        const set = new Set(slot.picks);
        const name = button.dataset.attrName;
        set.has(name) ? set.delete(name) : set.add(name);
        slot.picks = [...set];
        slot.confirmed = true;
        render();
      }));
      root.querySelector(`[data-attr-none="${concept.id}"]`)?.addEventListener("click", () => {
        slot.picks = [];
        slot.confirmed = true;
        render();
      });
    },
  };
}

function scoreDemo(laneId) {
  let r;
  if (laneId === "wc-pack-2") r = { score: 92, note: "Packaging Line 2 is a valid alternate, and the model keeps the Line 3 calendar issue open for data cleanup." };
  else if (laneId === "wc-pack-3") r = { score: 54, note: "Line 3 still has an unresolved calendar issue — it shouldn't run the rush order." };
  else r = { score: 28, note: "That resource doesn't perform packaging operations. The miss links to training and role readiness." };
  state.demo = { laneId, ...r };
  render();
}
